# [doc = " The `std.numerics` guarantee matrix (spec §4; RFC-0016 §4.5)."] # [doc = ""] # [doc = " Structural invariants are verified by [`assert_matrix_invariants`] and the `#[test]`s below."] pub const GUARANTEE_MATRIX : & [GuaranteeRow] = & [GuaranteeRow { op : "exact" , tag : GuaranteeStrength :: Exact , fallible : false , error_set : "total" , effects : "none" , explainable : false , } , GuaranteeRow { op : "value_of" , tag : GuaranteeStrength :: Exact , fallible : false , error_set : "total" , effects : "none" , explainable : false , } , GuaranteeRow { op : "bound_of" , tag : GuaranteeStrength :: Exact , fallible : false , error_set : "total" , effects : "none" , explainable : true , } , GuaranteeRow { op : "strength_of" , tag : GuaranteeStrength :: Exact , fallible : false , error_set : "total" , effects : "none" , explainable : true , } , GuaranteeRow { op : "error_bound" , tag : GuaranteeStrength :: Exact , fallible : true , error_set : "Err(NumErr::BadEps) when eps < 0 or non-finite" , effects : "none" , explainable : true , } , GuaranteeRow { op : "prob_bound" , tag : GuaranteeStrength :: Exact , fallible : true , error_set : "Err(NumErr::BadDelta) when delta not in [0,1] or non-finite" , effects : "none" , explainable : true , } , GuaranteeRow { op : "declared" , tag : GuaranteeStrength :: Declared , fallible : false , error_set : "total (the assertion never fails; it is unverified — M-I4/VR-5)" , effects : "none" , explainable : true , } , GuaranteeRow { op : "attach" , tag : GuaranteeStrength :: Exact , fallible : false , error_set : "total" , effects : "none" , explainable : true , } , GuaranteeRow { op : "combine" , tag : GuaranteeStrength :: Exact , fallible : true , error_set : "Err(NumErr::NoRule) when no sound ε rule; Err(NumErr::Overflow) on overflow" , effects : "none" , explainable : true , } , GuaranteeRow { op : "union_delta" , tag : GuaranteeStrength :: Exact , fallible : true , error_set : "Err(NumErr::NoRule) on empty input; Err(NumErr::BadDelta) on malformed input δ" , effects : "none" , explainable : true , } , GuaranteeRow { op : "accuracy_to_probability" , tag : GuaranteeStrength :: Exact , fallible : true , error_set : "Err(NumErr::NoRule) if input is not Error kind; Err(NumErr::BadDelta) if acc_delta not in [0,1]" , effects : "none" , explainable : true , } , GuaranteeRow { op : "explain" , tag : GuaranteeStrength :: Exact , fallible : false , error_set : "total" , effects : "none" , explainable : true , } , GuaranteeRow { op : "check_error" , tag : GuaranteeStrength :: Exact , fallible : true , error_set : "Err(CheckErr::Rejected{recomputed,claimed}) when claim is tighter than re-derivation; \
             Err(CheckErr::Malformed) when ill-formed" , effects : "none" , explainable : true , } , GuaranteeRow { op : "check_union" , tag : GuaranteeStrength :: Exact , fallible : true , error_set : "Err(CheckErr::Rejected{recomputed,claimed}) when claim is too tight; \
             Err(CheckErr::Malformed) on malformed input" , effects : "none" , explainable : true , } ,] ;
